class Solution:
    def regionsBySlashes(self, grid):
        n = len(grid)
        g = [[0] * (3 * n) for _ in range(3 * n)]
        for i in range(n):
            for j in range(n):
                c = grid[i][j]
                if c == '/':
                    g[3 * i][3 * j + 2] = 1
                    g[3 * i + 1][3 * j + 1] = 1
                    g[3 * i + 2][3 * j] = 1
                elif c == '\\':
                    g[3 * i][3 * j] = 1
                    g[3 * i + 1][3 * j + 1] = 1
                    g[3 * i + 2][3 * j + 2] = 1
        seen = [[False] * (3 * n) for _ in range(3 * n)]
        regions = 0
        for i in range(3 * n):
            for j in range(3 * n):
                if g[i][j] == 0 and not seen[i][j]:
                    regions += 1
                    stack = [(i, j)]
                    seen[i][j] = True
                    while stack:
                        x, y = stack.pop()
                        for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                            nx, ny = x + dx, y + dy
                            if 0 <= nx < 3 * n and 0 <= ny < 3 * n and g[nx][ny] == 0 and not seen[nx][ny]:
                                seen[nx][ny] = True
                                stack.append((nx, ny))
        return regions

