class Solution:
    def regionsBySlashes(self, grid):
        n = len(grid)
        parent = list(range(4 * n * n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        def idx(i, j, k):
            return (i * n + j) * 4 + k
        for i in range(n):
            for j in range(n):
                c = grid[i][j]
                if c == '/':
                    union(idx(i, j, 0), idx(i, j, 3))
                    union(idx(i, j, 1), idx(i, j, 2))
                elif c == '\\':
                    union(idx(i, j, 0), idx(i, j, 1))
                    union(idx(i, j, 2), idx(i, j, 3))
                else:
                    union(idx(i, j, 0), idx(i, j, 1))
                    union(idx(i, j, 1), idx(i, j, 2))
                    union(idx(i, j, 2), idx(i, j, 3))
                if j + 1 < n:
                    union(idx(i, j, 1), idx(i, j + 1, 3))
                if i + 1 < n:
                    union(idx(i, j, 2), idx(i + 1, j, 0))
        return sum(1 for x in range(4 * n * n) if find(x) == x)

