var regionsBySlashes = function(grid) {
    const n = grid.length;
    const parent = Array.from({length: 4 * n * n}, (_, i) => i);
    const find = (x) => {
        while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; }
        return x;
    };
    const union = (a, b) => { const ra = find(a), rb = find(b); if (ra !== rb) parent[ra] = rb; };
    const idx = (i, j, k) => (i * n + j) * 4 + k;
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            const c = grid[i][j];
            if (c === '/') {
                union(idx(i, j, 0), idx(i, j, 3));
                union(idx(i, j, 1), idx(i, j, 2));
            } else if (c === '\\') {
                union(idx(i, j, 0), idx(i, j, 1));
                union(idx(i, j, 2), idx(i, j, 3));
            } else {
                union(idx(i, j, 0), idx(i, j, 1));
                union(idx(i, j, 1), idx(i, j, 2));
                union(idx(i, j, 2), idx(i, j, 3));
            }
            if (j + 1 < n) union(idx(i, j, 1), idx(i, j + 1, 3));
            if (i + 1 < n) union(idx(i, j, 2), idx(i + 1, j, 0));
        }
    }
    let count = 0;
    for (let x = 0; x < 4 * n * n; x++) if (find(x) === x) count++;
    return count;
};
